sed -n '68,153p' .archon/proof-journal/current_session/attempts_raw.jsonl | python3 -c "
import sys,json
for line in sys.stdin:
    line=line.strip()
    if not line: continue
    try: o=json.loads(line)
    except: continue
    t=o.get('type','')
    if t=='code_change':
        f=o.get('file','').split('/')[-1]
        old=o.get('old_text','')[:60].replace(chr(10),' ')
        new=o.get('new_text','')[:80].replace(chr(10),' ')
        print(f'[EDIT {f}] {old!r} -> {new!r}')
    elif t=='build':
        print(f'[BUILD] err={o.get(\"has_errors\")} {o.get(\"result_preview\",\"\")[:200]}')
    elif t=='diagnostics':
        ec=o.get('error_count',0); 
        ep=(o.get('errors') or [''])[0][:150] if ec else 'clean'
        print(f'[DIAG err={ec}] {ep}')
    elif t=='goal_state':
        print(f'[GOAL line={o.get(\"line\")}]')
    elif t=='bash':
        print(f'[BASH] {o.get(\"command\",\"\")[:90]}')
    elif t=='file_read':
        pass
    else:
        print(f'[{t}] {str(o)[:100]}')
"

